// Ignore messages from bots or system events
if ($input.item.json.bot_id || $input.item.json.subtype) {
  return [];
}

const text = ($input.item.json.text || '').trim();

// Common intent patterns
const patterns = [
  /(?:find|search|look(?:ing)?\s+for)\s+(?:jobs?\s+(?:for|as)\s+)?(.+?)(?:\s+jobs?)?$/i,
  /jobs?\s+(?:for|as)\s+(.+)$/i,
  /looking\s+for\s+(.+?)\s+(?:jobs?|positions?|roles?)/i
];

let jobTitle = null;
for (const pattern of patterns) {
  const match = text.match(pattern);
  if (match) { jobTitle = match[1].trim(); break; }
}

// Fallback: short messages treated as direct job title input
if (!jobTitle && text.length > 0 && text.length < 80 && text.split(' ').length <= 7) {
  jobTitle = text;
}

return [{
  json: {
    jobTitle,
    found: jobTitle !== null,
    channel: $input.item.json.channel,
    thread_ts: $input.item.json.ts
  }
}];

const input = $input.first().json;
const jobs = (input.data || [])
  .sort((a, b) => new Date(b.job_posted_at || 0) - new Date(a.job_posted_at || 0))
  .slice(0, 5);

if (jobs.length === 0) {
  // Nothing found — signal will bubble up silently; add a Slack notify node if desired
  return [];
}

return jobs.map(job => ({
  json: {
    job_title: job.job_title || 'Unknown Title',
    employer_name: job.employer_name || 'Unknown Company',
    job_city: job.job_city || job.job_country || 'Remote',
    job_description: (job.job_description || '').slice(0, 4000),
    job_apply_link: job.job_apply_link || '',
    job_posted_at: job.job_posted_at || '',
    job_source: job.job_source || '',
    job_salary: job.job_min_salary
      ? `${job.job_min_salary}-${job.job_max_salary} ${job.job_salary_currency || 'USD'}`
      : 'Not listed'
  }
}));

// Combine job data (from Prepare Job List) with the downloaded template text
const jobData = $('Prepare Job List').item.json;
const binaryData = $input.item.binary?.data;

let templateText = 'NO TEMPLATE LOADED. Set your resume template File ID in the Get Resume Template node.';
if (binaryData?.data) {
  try {
    templateText = Buffer.from(binaryData.data, 'base64').toString('utf-8');
  } catch (e) { /* keep placeholder */ }
}

return [{ json: { ...jobData, resumeTemplate: templateText } }];

const job = $('Merge Template Data').item.json;
const resumeId = $('Save Resume to Drive').item.json.id;
const clId = $json.id; // cover letter file ID from current node (Save Cover Letter to Drive)

return [{
  json: {
    job_title: job.job_title,
    employer_name: job.employer_name,
    job_city: job.job_city,
    job_salary: job.job_salary,
    job_description: job.job_description,
    job_apply_link: job.job_apply_link,
    job_posted_at: job.job_posted_at,
    job_source: job.job_source,
    resumeLink: `https://drive.google.com/file/d/${resumeId}/view`,
    coverLetterLink: `https://drive.google.com/file/d/${clId}/view`
  }
}];

const job = $('Merge Template Data').item.json;
const resumeId = $('Save Resume to Drive').item.json.id;

return [{
  json: {
    job_title: job.job_title,
    employer_name: job.employer_name,
    job_city: job.job_city,
    job_salary: job.job_salary,
    job_description: job.job_description,
    job_apply_link: job.job_apply_link,
    job_posted_at: job.job_posted_at,
    job_source: job.job_source,
    resumeLink: `https://drive.google.com/file/d/${resumeId}/view`,
    coverLetterLink: null
  }
}];

const items = $input.all();
const channel = $('Extract Job Title').first().json.channel;
const thread_ts = $('Extract Job Title').first().json.thread_ts;

let msg = `*Found ${items.length} job match${items.length !== 1 ? 'es' : ''} — your tailored application kit is ready!*\n\n`;

items.forEach((item, i) => {
  const j = item.json;
  const files = [`<${j.resumeLink}|Tailored Resume>`];
  if (j.coverLetterLink) {
    files.push(`<${j.coverLetterLink}|Cover Letter (Upwork)>`);
  }
  msg += `*${i + 1}. ${j.job_title}* @ ${j.employer_name}\n`;
  msg += `Location: ${j.job_city} | Pay: ${j.job_salary}\n`;
  msg += `Posted: ${j.job_posted_at} | Source: ${j.job_source}\n`;
  msg += `<${j.job_apply_link}|Apply Here>  |  ${files.join('  |  ')}\n`;
  msg += `\n_${(j.job_description || '').slice(0, 300).replace(/\n/g, ' ')}..._\n`;
  if (i < items.length - 1) msg += `\n---\n\n`;
});

return [{ json: { message: msg, channel, thread_ts } }];
